import { useState, useEffect } from 'react';
import { Moon, Sun, Menu, X } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

export default function Navbar() {
  const { dark, setDark, lang, setLang } = useApp();
  const tr = t[lang];
  const [scrolled, setScrolled] = useState(false);
  const [active, setActive] = useState('');
  const [menuOpen, setMenuOpen] = useState(false);

  const links = [
    { id:'about',      label: tr.about },
    { id:'projects',   label: tr.projectsNav },
    { id:'experience', label: tr.experience },
    { id:'certs',      label: tr.certs },
    { id:'contact',    label: tr.contact },
  ];

  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 40);
      let cur = '';
      document.querySelectorAll('section[id]').forEach(s => {
        if (window.scrollY >= s.offsetTop - 130) cur = s.id;
      });
      setActive(cur);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const navBg = scrolled
    ? dark ? 'bg-[#0f0f14]/92 backdrop-blur-lg border-b border-white/5 shadow-sm'
           : 'bg-[#fdfcf9]/92 backdrop-blur-lg border-b border-ink/5 shadow-sm'
    : 'bg-transparent';

  const linkColor = (id) => active === id ? 'text-amber' : dark ? 'text-white/60 hover:text-amber' : 'text-muted2 hover:text-amber';

  return (
    <nav className={`fixed inset-x-0 top-0 z-50 flex items-center justify-between px-[5%] py-4 transition-all duration-300 ${navBg}`}>

      {/* Logo — KeMoO */}
      <a href="#hero" className="font-serif-display text-2xl tracking-tight">
        <span className={dark ? 'text-white' : 'text-ink'}>Ke</span>
        <span className="text-amber">Mo</span>
        <span className={dark ? 'text-white' : 'text-ink'}>O</span>
        <span className="text-amber">.</span>
      </a>

      {/* Desktop links */}
      <ul className="hidden md:flex gap-7">
        {links.map(l => (
          <li key={l.id}>
            <a href={`#${l.id}`} className={`text-sm font-medium transition-colors duration-200 ${linkColor(l.id)}`}>
              {l.label}
            </a>
          </li>
        ))}
      </ul>

      {/* Controls */}
      <div className="flex items-center gap-2">
        {/* Language toggle */}
        <button
          onClick={() => setLang(lang === 'en' ? 'ar' : 'en')}
          className={`px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${
            dark ? 'border-white/15 text-white/60 hover:border-amber hover:text-amber'
                 : 'border-ink/15 text-muted2 hover:border-amber hover:text-amber'
          }`}>
          {lang === 'en' ? 'ع' : 'EN'}
        </button>

        {/* Dark mode */}
        <button
          onClick={() => setDark(!dark)}
          className={`w-9 h-9 rounded-full border flex items-center justify-center transition-all ${
            dark ? 'border-white/15 text-amber hover:border-amber bg-white/5'
                 : 'border-ink/15 text-muted2 hover:border-amber hover:text-amber'
          }`}>
          {dark ? <Sun size={15}/> : <Moon size={15}/>}
        </button>

        {/* Hire Me */}
        <a href="mailto:karemalwy1@gmail.com"
          className={`hidden md:inline-block px-4 py-2 text-sm font-semibold rounded-full transition-all hover:bg-amber hover:-translate-y-0.5 ${
            dark ? 'bg-white/10 text-white border border-white/15 hover:border-transparent'
                 : 'bg-ink text-parchment'
          }`}>
          {tr.hireMe}
        </a>

        {/* Mobile menu button */}
        <button className="md:hidden" onClick={() => setMenuOpen(!menuOpen)}>
          {menuOpen
            ? <X size={22} className={dark ? 'text-white' : 'text-ink'}/>
            : <Menu size={22} className={dark ? 'text-white' : 'text-ink'}/>}
        </button>
      </div>

      {/* Mobile dropdown */}
      {menuOpen && (
        <div className={`absolute top-full left-0 right-0 border-b py-4 flex flex-col items-center gap-4 md:hidden ${
          dark ? 'bg-[#0f0f14] border-white/10' : 'bg-parchment border-ink/10'
        }`}>
          {links.map(l => (
            <a key={l.id} href={`#${l.id}`} onClick={() => setMenuOpen(false)}
              className={`text-sm font-medium transition-colors ${linkColor(l.id)}`}>
              {l.label}
            </a>
          ))}
          <a href="mailto:karemalwy1@gmail.com"
            className={`px-5 py-2 text-sm font-semibold rounded-full ${dark ? 'bg-white text-[#0f0f14]' : 'bg-ink text-parchment'}`}>
            {tr.hireMe}
          </a>
        </div>
      )}
    </nav>
  );
}
